private static String cacheString(final char[] charBuf, final String[] stringCache, final int start, final int count) {
    // Early returns for edge cases:
    if (charBuf == null || stringCache == null || start < 0 || count < 0 || start >= charBuf.length) {
        return "";
    }
    // Adjust count to not exceed bounds
    int effectiveCount = Math.min(count, charBuf.length - start);
    // Limit (no cache):
    if (effectiveCount > maxStringCacheLen) {
        return new String(charBuf, start, effectiveCount);
    }
    // Calculate hash:
    int hash = 0;
    int offset = start;
    for (int i = 0; i < effectiveCount; i++) {
        hash = 31 * hash + charBuf[offset++];
    }
    // Get from cache
    final int index = hash & (stringCache.length - 1);
    String cached = stringCache[index];
    if (cached == null) { // miss, add
        cached = new String(charBuf, start, effectiveCount);
        stringCache[index] = cached;
    } else { // hashcode hit, check equality
        if (rangeEquals(charBuf, start, effectiveCount, cached)) { // hit
            return cached;
        } else { // hashcode conflict
            cached = new String(charBuf, start, effectiveCount);
            stringCache[index] = cached; // update the cache, as recently used strings are more likely to show up again
        }
    }
    return cached;
}

